create extension if not exists pgcrypto;
create extension if not exists citext;
create type school_level as enum ('middle_school','high_school','college','graduate','other');
create type asset_type as enum ('typed_note','image_note','audio_note','uploaded_pdf','summary','flashcard_set','quiz','mock_test');
create type quiz_mode as enum ('practice','timed','exam');
create type reminder_type as enum ('exam','assignment','study_session','meeting','custom');
create type reminder_status as enum ('scheduled','sent','cancelled');
create type message_role as enum ('system','user','assistant','tool');
create or replace function set_updated_at() returns trigger as $$ begin new.updated_at = now(); return new; end; $$ language plpgsql;
create table users (id uuid primary key default gen_random_uuid(), email citext not null unique, google_id text unique, password_hash text, full_name text, role text not null default 'student', auth_provider text not null default 'email', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_users_updated_at before update on users for each row execute function set_updated_at();
create table student_profiles (user_id uuid primary key references users(id) on delete cascade, school_name text, school_level school_level not null default 'other', grade_year text, major text, timezone text not null default 'America/New_York', learning_style text, onboarding_complete boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_student_profiles_updated_at before update on student_profiles for each row execute function set_updated_at();
create table subjects (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, name text not null, teacher_name text, color text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(user_id,name));
create index idx_subjects_user_id on subjects(user_id);
create trigger trg_subjects_updated_at before update on subjects for each row execute function set_updated_at();
create table agent_profiles (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references users(id) on delete cascade, openclaw_agent_id text not null unique, model_key text not null default 'gpt-5', persona_name text not null default 'StudyClaw', tone text not null default 'supportive', verbosity text not null default 'concise', teaching_style text not null default 'step-by-step', reminder_style text not null default 'proactive', system_prompt text not null, preset_key text, custom_instructions text, core_traits_version text not null default 'v1', last_reset_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_agent_profiles_updated_at before update on agent_profiles for each row execute function set_updated_at();
create table agents (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references users(id) on delete cascade, openclaw_agent_id text not null unique, name varchar(100) not null default 'My Study Agent', agent_type varchar(20) not null check (agent_type in ('custom', 'quick_start_1', 'quick_start_2')), config jsonb not null default '{}'::jsonb, status varchar(20) not null default 'active' check (status in ('active', 'disabled', 'reset_pending')), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index idx_agents_user_id on agents(user_id);
create index idx_agents_status on agents(status);
create trigger trg_agents_updated_at before update on agents for each row execute function set_updated_at();
create table study_assets (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, subject_id uuid references subjects(id) on delete set null, asset_type asset_type not null, title text not null, original_text text, processed_text text, file_url text, metadata_json jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index idx_study_assets_user_type on study_assets(user_id, asset_type, created_at desc);
create trigger trg_study_assets_updated_at before update on study_assets for each row execute function set_updated_at();
create table flashcard_sets (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, subject_id uuid references subjects(id) on delete set null, source_asset_id uuid references study_assets(id) on delete set null, title text not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_flashcard_sets_updated_at before update on flashcard_sets for each row execute function set_updated_at();
create table flashcards (id uuid primary key default gen_random_uuid(), set_id uuid not null references flashcard_sets(id) on delete cascade, front text not null, back text not null, difficulty smallint, created_at timestamptz not null default now());
create table quizzes (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, subject_id uuid references subjects(id) on delete set null, source_asset_id uuid references study_assets(id) on delete set null, title text not null, mode quiz_mode not null default 'practice', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_quizzes_updated_at before update on quizzes for each row execute function set_updated_at();
create table quiz_questions (id uuid primary key default gen_random_uuid(), quiz_id uuid not null references quizzes(id) on delete cascade, question_text text not null, question_type text not null default 'multiple_choice', choices_json jsonb, answer_json jsonb, explanation text, created_at timestamptz not null default now());
create table chat_threads (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, openclaw_session_id text not null, title text, last_message_at timestamptz not null default now(), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_chat_threads_updated_at before update on chat_threads for each row execute function set_updated_at();
create table chat_messages (id uuid primary key default gen_random_uuid(), thread_id uuid not null references chat_threads(id) on delete cascade, role message_role not null, content text not null, metadata_json jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table reminders (id uuid primary key default gen_random_uuid(), user_id uuid not null references users(id) on delete cascade, type reminder_type not null, title text not null, reminder_at timestamptz not null, status reminder_status not null default 'scheduled', metadata_json jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_reminders_updated_at before update on reminders for each row execute function set_updated_at();
create table user_model_credentials (user_id uuid primary key references users(id) on delete cascade, provider_id text not null, api_key text, oauth_connected boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_user_model_credentials_updated_at before update on user_model_credentials for each row execute function set_updated_at();
create table user_google_tokens (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references users(id) on delete cascade, google_subject text not null, google_email citext, access_token text not null, refresh_token text, scope text not null, token_type text not null default 'Bearer', expires_at timestamptz not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index idx_user_google_tokens_user_id on user_google_tokens(user_id);
create trigger trg_user_google_tokens_updated_at before update on user_google_tokens for each row execute function set_updated_at();
create table agent_actions (id uuid primary key default gen_random_uuid(), agent_id uuid not null references agents(id) on delete cascade, action_type varchar(50) not null, summary text not null, payload jsonb, created_at timestamptz not null default now());
create index idx_agent_actions_agent_id on agent_actions(agent_id);
create index idx_agent_actions_created_at on agent_actions(created_at desc);
create table admin_agents (id uuid primary key default gen_random_uuid(), owner_user_id uuid unique references users(id) on delete cascade, openclaw_agent_id text not null unique, config jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create trigger trg_admin_agents_updated_at before update on admin_agents for each row execute function set_updated_at();
